export class PinApi {
    constructor(ctx) {
        this.ctx = ctx;
    }
    /**
     * GET: /pins
     * @ru Получить закреплённые сущности пользователя.
     * @en Get user pinned entities.
     * @returns Promise with pinned items.
     */
    getPins() {
        return this.ctx.get(this.ctx.createRequest("/pins"));
    }
}
